const fs = require('node:fs');
const path = require('node:path');
const { MANAGER_DIR_NAME } = require('./paths');

// Port of the ~/.protovibe/launch.sh staged-update swap (generated by
// protovibe-project-manager/scripts/create-shortcut.js): the in-app updater
// stages a new manager into protovibe-project-manager.pending/ because the
// running vite can't see its own files change; before vite boots we swap the
// dirs, carry node_modules across, and reconcile deps.
async function applyStagedUpdate(root, runPnpm, log = () => {}) {
  const pm = path.join(root, MANAGER_DIR_NAME);
  const pending = `${pm}.pending`;
  const old = `${pm}.old`;
  if (!fs.existsSync(pending)) return false;

  log('Applying staged project-manager update…');
  const liveModules = path.join(pm, 'node_modules');
  const pendingModules = path.join(pending, 'node_modules');
  if (fs.existsSync(liveModules) && !fs.existsSync(pendingModules)) {
    fs.renameSync(liveModules, pendingModules);
  }
  fs.rmSync(old, { recursive: true, force: true });
  try {
    fs.renameSync(pm, old);
    fs.renameSync(pending, pm);
  } catch (err) {
    log('Failed to apply staged update; reverting.');
    if (fs.existsSync(old) && !fs.existsSync(pm)) fs.renameSync(old, pm);
    throw err;
  }
  fs.rmSync(old, { recursive: true, force: true });
  log('Installing dependencies…');
  await runPnpm(['--dir', pm, 'install', '--prefer-offline'], root);
  return true;
}

module.exports = { applyStagedUpdate };
